/**
 * Unit tests for AddContentForm component.
 *
 * Tests cover the core "paste in URL" functionality:
 * - Rendering the form
 * - URL input and validation
 * - Submitting URLs
 * - Success and error handling
 * - Loading states
 * - Form reset after success
 */

import React from "react";
import { render, screen, fireEvent, waitFor } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import "@testing-library/jest-dom";
import AddContentForm from "../../components/AddContentForm";
import { contentAPI } from "../../lib/api";

// Mock the API module
jest.mock("../../lib/api");
const mockedContentAPI = contentAPI as jest.Mocked<typeof contentAPI>;

// Mock the ToastContext
const mockShowToast = jest.fn();
jest.mock("../../contexts/ToastContext", () => ({
  useToast: () => ({ showToast: mockShowToast }),
}));

describe("AddContentForm", () => {
  const mockOnContentAdded = jest.fn();

  beforeEach(() => {
    jest.clearAllMocks();
  });

  describe("Rendering", () => {
    it("renders form with URL input and submit button", () => {
      render(<AddContentForm onContentAdded={mockOnContentAdded} />);

      expect(screen.getByLabelText(/url/i)).toBeInTheDocument();
      expect(
        screen.getByPlaceholderText(/https:\/\/example.com\/article/i),
      ).toBeInTheDocument();
      expect(
        screen.getByRole("button", { name: /add to queue/i }),
      ).toBeInTheDocument();
    });

    it("renders URL input with required attribute", () => {
      render(<AddContentForm onContentAdded={mockOnContentAdded} />);

      const input = screen.getByLabelText(/url/i);
      expect(input).toBeRequired();
      expect(input).toHaveAttribute("type", "url");
    });

    it("does not show error message initially", () => {
      render(<AddContentForm onContentAdded={mockOnContentAdded} />);

      const errorDiv = screen.queryByRole("alert");
      expect(errorDiv).not.toBeInTheDocument();
    });
  });

  describe("URL Input", () => {
    it("allows user to type URL", async () => {
      render(<AddContentForm onContentAdded={mockOnContentAdded} />);

      const input = screen.getByLabelText(/url/i);
      await userEvent.type(input, "https://example.com/article");

      expect(input).toHaveValue("https://example.com/article");
    });

    it("updates input value on change", async () => {
      render(<AddContentForm onContentAdded={mockOnContentAdded} />);

      const input = screen.getByLabelText(/url/i);
      await userEvent.type(input, "https://news.ycombinator.com");

      expect(input).toHaveValue("https://news.ycombinator.com");
    });
  });

  describe("Form Submission - Success", () => {
    it("submits URL and shows success message", async () => {
      mockedContentAPI.create.mockResolvedValue({
        id: "new-content-123",
        original_url: "https://example.com/article",
        processing_status: "pending",
        is_read: false,
        is_archived: false,
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
      });

      render(<AddContentForm onContentAdded={mockOnContentAdded} />);

      const input = screen.getByLabelText(/url/i);
      const submitButton = screen.getByRole("button", {
        name: /add to queue/i,
      });

      await userEvent.type(input, "https://example.com/article");
      fireEvent.click(submitButton);

      await waitFor(() => {
        expect(mockedContentAPI.create).toHaveBeenCalledWith({
          url: "https://example.com/article",
        });

        expect(mockShowToast).toHaveBeenCalledWith(
          "Article added successfully!",
          "success",
        );

        expect(mockOnContentAdded).toHaveBeenCalled();
      });
    });

    it("clears input after successful submission", async () => {
      mockedContentAPI.create.mockResolvedValue({
        id: "new-content-123",
        original_url: "https://example.com/article",
        processing_status: "pending",
        is_read: false,
        is_archived: false,
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
      });

      render(<AddContentForm onContentAdded={mockOnContentAdded} />);

      const input = screen.getByLabelText(/url/i);
      await userEvent.type(input, "https://example.com/article");

      const submitButton = screen.getByRole("button", {
        name: /add to queue/i,
      });
      fireEvent.click(submitButton);

      await waitFor(() => {
        expect(input).toHaveValue("");
      });
    });

    it("shows loading state during submission", async () => {
      // Create a promise we can control
      let resolveCreate: any;
      const createPromise = new Promise((resolve) => {
        resolveCreate = resolve;
      });
      mockedContentAPI.create.mockReturnValue(createPromise as any);

      render(<AddContentForm onContentAdded={mockOnContentAdded} />);

      const input = screen.getByLabelText(/url/i);
      await userEvent.type(input, "https://example.com/article");

      const submitButton = screen.getByRole("button", {
        name: /add to queue/i,
      });
      fireEvent.click(submitButton);

      // While loading
      await waitFor(() => {
        expect(screen.getByText(/adding.../i)).toBeInTheDocument();
        expect(submitButton).toBeDisabled();
      });

      // Resolve the promise
      resolveCreate({
        id: "new-content-123",
        original_url: "https://example.com/article",
        processing_status: "pending",
        is_read: false,
        is_archived: false,
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
      });

      // After loading
      await waitFor(() => {
        expect(screen.getByText(/add to queue/i)).toBeInTheDocument();
        expect(submitButton).not.toBeDisabled();
      });
    });
  });

  describe("Form Submission - Error", () => {
    it("shows error message when submission fails", async () => {
      mockedContentAPI.create.mockRejectedValue(new Error("Network error"));

      render(<AddContentForm onContentAdded={mockOnContentAdded} />);

      const input = screen.getByLabelText(/url/i);
      await userEvent.type(input, "https://example.com/article");

      const submitButton = screen.getByRole("button", {
        name: /add to queue/i,
      });
      fireEvent.click(submitButton);

      await waitFor(() => {
        expect(screen.getByText(/network error/i)).toBeInTheDocument();
        expect(mockShowToast).toHaveBeenCalledWith("Network error", "error");
      });
    });

    it("shows generic error message for unknown errors", async () => {
      mockedContentAPI.create.mockRejectedValue("Unknown error");

      render(<AddContentForm onContentAdded={mockOnContentAdded} />);

      const input = screen.getByLabelText(/url/i);
      await userEvent.type(input, "https://example.com/article");

      const submitButton = screen.getByRole("button", {
        name: /add to queue/i,
      });
      fireEvent.click(submitButton);

      await waitFor(() => {
        expect(
          screen.getByText(/failed to add content. please try again/i),
        ).toBeInTheDocument();
      });
    });

    it("does not clear input when submission fails", async () => {
      mockedContentAPI.create.mockRejectedValue(new Error("Server error"));

      render(<AddContentForm onContentAdded={mockOnContentAdded} />);

      const input = screen.getByLabelText(/url/i);
      const testUrl = "https://example.com/article";
      await userEvent.type(input, testUrl);

      const submitButton = screen.getByRole("button", {
        name: /add to queue/i,
      });
      fireEvent.click(submitButton);

      await waitFor(() => {
        expect(input).toHaveValue(testUrl); // URL still there so user can retry
      });
    });

    it("does not call onContentAdded when submission fails", async () => {
      mockedContentAPI.create.mockRejectedValue(new Error("Server error"));

      render(<AddContentForm onContentAdded={mockOnContentAdded} />);

      const input = screen.getByLabelText(/url/i);
      await userEvent.type(input, "https://example.com/article");

      const submitButton = screen.getByRole("button", {
        name: /add to queue/i,
      });
      fireEvent.click(submitButton);

      await waitFor(() => {
        expect(screen.getByText(/server error/i)).toBeInTheDocument();
      });

      expect(mockOnContentAdded).not.toHaveBeenCalled();
    });

    it("shows error message for rate limiting", async () => {
      mockedContentAPI.create.mockRejectedValue(
        new Error("Too many requests. Please slow down."),
      );

      render(<AddContentForm onContentAdded={mockOnContentAdded} />);

      const input = screen.getByLabelText(/url/i);
      await userEvent.type(input, "https://example.com/article");

      const submitButton = screen.getByRole("button", {
        name: /add to queue/i,
      });
      fireEvent.click(submitButton);

      await waitFor(() => {
        expect(
          screen.getByText(/too many requests. please slow down/i),
        ).toBeInTheDocument();
      });
    });
  });

  describe("Form Validation", () => {
    it("prevents submission when URL is empty", async () => {
      render(<AddContentForm onContentAdded={mockOnContentAdded} />);

      const submitButton = screen.getByRole("button", {
        name: /add to queue/i,
      });
      fireEvent.click(submitButton);

      // HTML5 validation should prevent submission
      // The API should not be called
      await waitFor(() => {
        expect(mockedContentAPI.create).not.toHaveBeenCalled();
      });
    });

    it("accepts various URL formats", async () => {
      mockedContentAPI.create.mockResolvedValue({
        id: "new-content-123",
        original_url: "",
        processing_status: "pending",
        is_read: false,
        is_archived: false,
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
      });

      const urls = [
        "https://example.com/article",
        "http://blog.example.com/post/123",
        "https://subdomain.example.com/path/to/page",
        "https://example.com/article?param=value&other=test",
      ];

      for (const url of urls) {
        const { unmount } = render(
          <AddContentForm onContentAdded={mockOnContentAdded} />,
        );

        const input = screen.getByLabelText(/url/i);
        await userEvent.type(input, url);

        const submitButton = screen.getByRole("button", {
          name: /add to queue/i,
        });
        fireEvent.click(submitButton);

        await waitFor(() => {
          expect(mockedContentAPI.create).toHaveBeenCalledWith({ url });
          expect(submitButton).not.toBeDisabled();
        });

        unmount();
        jest.clearAllMocks();
      }
    });
  });

  describe("User Experience", () => {
    it("focuses on input when component mounts", () => {
      render(<AddContentForm onContentAdded={mockOnContentAdded} />);

      // Input should be focusable (though not auto-focused in tests)
      const input = screen.getByLabelText(/url/i);
      expect(input).toBeInTheDocument();
      input.focus();
      expect(input).toHaveFocus();
    });

    it("allows form submission by pressing Enter", async () => {
      mockedContentAPI.create.mockResolvedValue({
        id: "new-content-123",
        original_url: "https://example.com/article",
        processing_status: "pending",
        is_read: false,
        is_archived: false,
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
      });

      render(<AddContentForm onContentAdded={mockOnContentAdded} />);

      const input = screen.getByLabelText(/url/i);
      await userEvent.type(input, "https://example.com/article{Enter}");

      await waitFor(() => {
        expect(mockedContentAPI.create).toHaveBeenCalled();
      });
    });

    it("disables button during submission to prevent double-submit", async () => {
      let resolveCreate: any;
      const createPromise = new Promise((resolve) => {
        resolveCreate = resolve;
      });
      mockedContentAPI.create.mockReturnValue(createPromise as any);

      render(<AddContentForm onContentAdded={mockOnContentAdded} />);

      const input = screen.getByLabelText(/url/i);
      await userEvent.type(input, "https://example.com/article");

      const submitButton = screen.getByRole("button", {
        name: /add to queue/i,
      });
      fireEvent.click(submitButton);

      await waitFor(() => {
        expect(submitButton).toBeDisabled();
      });

      // Try to click again
      fireEvent.click(submitButton);

      // Should only be called once
      expect(mockedContentAPI.create).toHaveBeenCalledTimes(1);

      // Resolve
      resolveCreate({
        id: "new-content-123",
        original_url: "https://example.com/article",
        processing_status: "pending",
        is_read: false,
        is_archived: false,
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
      });
    });
  });

  describe("Integration", () => {
    it("completes full submission flow", async () => {
      mockedContentAPI.create.mockResolvedValue({
        id: "new-content-123",
        original_url: "https://example.com/great-article",
        processing_status: "pending",
        is_read: false,
        is_archived: false,
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
      });

      render(<AddContentForm onContentAdded={mockOnContentAdded} />);

      // 1. Type URL
      const input = screen.getByLabelText(/url/i);
      await userEvent.type(input, "https://example.com/great-article");
      expect(input).toHaveValue("https://example.com/great-article");

      // 2. Submit
      const submitButton = screen.getByRole("button", {
        name: /add to queue/i,
      });
      fireEvent.click(submitButton);

      // 3. Verify loading state
      await waitFor(() => {
        expect(submitButton).toBeDisabled();
        expect(screen.getByText(/adding.../i)).toBeInTheDocument();
      });

      // 4. Verify success
      await waitFor(() => {
        expect(mockedContentAPI.create).toHaveBeenCalledWith({
          url: "https://example.com/great-article",
        });
        expect(mockShowToast).toHaveBeenCalledWith(
          "Article added successfully!",
          "success",
        );
        expect(mockOnContentAdded).toHaveBeenCalled();
        expect(input).toHaveValue("");
        expect(submitButton).not.toBeDisabled();
      });
    });
  });
});

/**
 * Unit tests for ContentItem component.
 *
 * Tests cover content display and interaction:
 * - Rendering content information
 * - Status badges (read/unread, archived)
 * - Mark as read/unread functionality
 * - Archive/unarchive functionality
 * - Tag management (add/remove tags)
 * - Delete confirmation
 * - Add to list functionality
 * - Processing status display
 */

import React from "react";
import { render, screen, fireEvent, waitFor } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import "@testing-library/jest-dom";
import ContentItem from "../../components/ContentItem";
import { ContentItem as ContentItemType } from "../../types";
import { contentAPI } from "../../lib/api";

// Mock Next.js Link component
jest.mock("next/link", () => {
  return ({ children, href }: any) => {
    return <a href={href}>{children}</a>;
  };
});

// Mock the API module
jest.mock("../../lib/api");
const mockedContentAPI = contentAPI as jest.Mocked<typeof contentAPI>;

// Mock the ToastContext
const mockShowToast = jest.fn();
jest.mock("../../contexts/ToastContext", () => ({
  useToast: () => ({ showToast: mockShowToast }),
}));

// Mock window.location.reload
delete (window as any).location;
(window as any).location = { reload: jest.fn() };

describe("ContentItem", () => {
  const mockOnStatusChange = jest.fn();
  const mockOnDelete = jest.fn();
  const mockOnRemoveFromList = jest.fn();
  const mockOnAddToList = jest.fn();

  const mockContent: ContentItemType = {
    id: "test-content-123",
    user_id: "test-user-123",
    content_type: "article",
    full_text: "Full text content...",
    word_count: 100,
    original_url: "https://example.com/article",
    title: "Test Article Title",
    description: "This is a test article description",

    is_read: false,
    is_archived: false,
    processing_status: "completed",
    created_at: new Date("2024-01-15T10:00:00Z").toISOString(),
    updated_at: new Date("2024-01-15T10:00:00Z").toISOString(),
    reading_time_minutes: 5,
    tags: ["javascript", "testing"],
    thumbnail_url: "https://example.com/thumb.jpg",
  };

  beforeEach(() => {
    jest.clearAllMocks();
  });

  describe("Rendering - Basic Information", () => {
    it("renders content title", () => {
      render(
        <ContentItem
          content={mockContent}
          onStatusChange={mockOnStatusChange}
          onDelete={mockOnDelete}
        />,
      );

      expect(screen.getByText("Test Article Title")).toBeInTheDocument();
    });

    it("renders description when available", () => {
      render(
        <ContentItem
          content={mockContent}
          onStatusChange={mockOnStatusChange}
          onDelete={mockOnDelete}
        />,
      );

      expect(
        screen.getByText("This is a test article description"),
      ).toBeInTheDocument();
    });

    it('shows "Untitled" when no title provided', () => {
      const contentWithoutTitle = { ...mockContent, title: null };

      render(
        <ContentItem
          content={contentWithoutTitle}
          onStatusChange={mockOnStatusChange}
          onDelete={mockOnDelete}
        />,
      );

      expect(screen.getByText("Untitled")).toBeInTheDocument();
    });

    it("renders thumbnail when available", () => {
      render(
        <ContentItem
          content={mockContent}
          onStatusChange={mockOnStatusChange}
          onDelete={mockOnDelete}
        />,
      );

      const thumbnail = screen.getByRole("img");
      expect(thumbnail).toHaveAttribute("src", "https://example.com/thumb.jpg");
    });

    it("does not render thumbnail when not available", () => {
      const contentWithoutThumbnail = {
        ...mockContent,
        thumbnail_url: null,
      };

      render(
        <ContentItem
          content={contentWithoutThumbnail}
          onStatusChange={mockOnStatusChange}
          onDelete={mockOnDelete}
        />,
      );

      expect(screen.queryByRole("img")).not.toBeInTheDocument();
    });

    it("shows reading time when available", () => {
      render(
        <ContentItem
          content={mockContent}
          onStatusChange={mockOnStatusChange}
          onDelete={mockOnDelete}
        />,
      );

      expect(screen.getByText(/5 min read/)).toBeInTheDocument();
    });

    it("links to reader view", () => {
      render(
        <ContentItem
          content={mockContent}
          onStatusChange={mockOnStatusChange}
          onDelete={mockOnDelete}
        />,
      );

      const link = screen.getByRole("link");
      expect(link).toHaveAttribute("href", "/content/test-content-123");
    });
  });

  describe("Status Badges", () => {
    it('shows "Unread" badge when not read', () => {
      render(
        <ContentItem
          content={mockContent}
          onStatusChange={mockOnStatusChange}
          onDelete={mockOnDelete}
        />,
      );

      expect(screen.getByText("Unread")).toBeInTheDocument();
      expect(screen.getByText("Unread")).toHaveClass(
        "bg-blue-100",
        "text-blue-800",
      );
    });

    it('shows "Read" badge when read', () => {
      const readContent = { ...mockContent, is_read: true };

      render(
        <ContentItem
          content={readContent}
          onStatusChange={mockOnStatusChange}
          onDelete={mockOnDelete}
        />,
      );

      expect(screen.getByText("Read")).toBeInTheDocument();
      expect(screen.getByText("Read")).toHaveClass(
        "bg-green-100",
        "text-green-800",
      );
    });

    it('shows "Archived" badge when archived', () => {
      const archivedContent = { ...mockContent, is_archived: true };

      render(
        <ContentItem
          content={archivedContent}
          onStatusChange={mockOnStatusChange}
          onDelete={mockOnDelete}
        />,
      );

      expect(screen.getByText("Archived")).toBeInTheDocument();
      expect(screen.getByText("Archived")).toHaveClass(
        "bg-gray-100",
        "text-gray-800",
      );
    });

    it("prioritizes archived status over read status", () => {
      const archivedReadContent = {
        ...mockContent,
        is_read: true,
        is_archived: true,
      };

      render(
        <ContentItem
          content={archivedReadContent}
          onStatusChange={mockOnStatusChange}
          onDelete={mockOnDelete}
        />,
      );

      expect(screen.getByText("Archived")).toBeInTheDocument();
      expect(screen.queryByText("Read")).not.toBeInTheDocument();
    });
  });

  describe("Processing Status", () => {
    it("shows pending status badge", () => {
      const pendingContent = { ...mockContent, processing_status: "pending" };

      render(
        <ContentItem
          content={pendingContent}
          onStatusChange={mockOnStatusChange}
          onDelete={mockOnDelete}
        />,
      );

      expect(screen.getByText("pending")).toBeInTheDocument();
      expect(screen.getByText("pending")).toHaveClass("animate-pulse");
    });

    it("shows processing status badge", () => {
      const processingContent = {
        ...mockContent,
        processing_status: "processing",
      };

      render(
        <ContentItem
          content={processingContent}
          onStatusChange={mockOnStatusChange}
          onDelete={mockOnDelete}
        />,
      );

      expect(screen.getByText("processing")).toBeInTheDocument();
      expect(screen.getByText("processing")).toHaveClass("animate-pulse");
    });

    it("shows failed status badge", () => {
      const failedContent = { ...mockContent, processing_status: "failed" };

      render(
        <ContentItem
          content={failedContent}
          onStatusChange={mockOnStatusChange}
          onDelete={mockOnDelete}
        />,
      );

      expect(screen.getByText("failed")).toBeInTheDocument();
    });

    it("does not show badge when processing is completed", () => {
      render(
        <ContentItem
          content={mockContent}
          onStatusChange={mockOnStatusChange}
          onDelete={mockOnDelete}
        />,
      );

      expect(screen.queryByText("completed")).not.toBeInTheDocument();
    });
  });

  describe("Mark as Read/Unread", () => {
    it("calls onStatusChange when marking as read", () => {
      render(
        <ContentItem
          content={mockContent}
          onStatusChange={mockOnStatusChange}
          onDelete={mockOnDelete}
        />,
      );

      const readButton = screen.getByTitle("Mark as read");
      fireEvent.click(readButton);

      expect(mockOnStatusChange).toHaveBeenCalledWith("test-content-123", {
        is_read: true,
      });
    });

    it("calls onStatusChange when marking as unread", () => {
      const readContent = { ...mockContent, is_read: true };

      render(
        <ContentItem
          content={readContent}
          onStatusChange={mockOnStatusChange}
          onDelete={mockOnDelete}
        />,
      );

      const unreadButton = screen.getByTitle("Mark as unread");
      fireEvent.click(unreadButton);

      expect(mockOnStatusChange).toHaveBeenCalledWith("test-content-123", {
        is_read: false,
      });
    });
  });

  describe("Archive/Unarchive", () => {
    it("calls onStatusChange when archiving", () => {
      render(
        <ContentItem
          content={mockContent}
          onStatusChange={mockOnStatusChange}
          onDelete={mockOnDelete}
        />,
      );

      const archiveButton = screen.getByTitle("Archive");
      fireEvent.click(archiveButton);

      expect(mockOnStatusChange).toHaveBeenCalledWith("test-content-123", {
        is_archived: true,
      });
    });

    it("calls onStatusChange when unarchiving", () => {
      const archivedContent = { ...mockContent, is_archived: true };

      render(
        <ContentItem
          content={archivedContent}
          onStatusChange={mockOnStatusChange}
          onDelete={mockOnDelete}
        />,
      );

      const unarchiveButton = screen.getByTitle("Unarchive");
      fireEvent.click(unarchiveButton);

      expect(mockOnStatusChange).toHaveBeenCalledWith("test-content-123", {
        is_archived: false,
      });
    });
  });

  describe("Tag Management", () => {
    it("displays existing tags", () => {
      render(
        <ContentItem
          content={mockContent}
          onStatusChange={mockOnStatusChange}
          onDelete={mockOnDelete}
        />,
      );

      expect(screen.getByText("javascript")).toBeInTheDocument();
      expect(screen.getByText("testing")).toBeInTheDocument();
    });

    it('shows "+ Tag" button to add new tags', () => {
      render(
        <ContentItem
          content={mockContent}
          onStatusChange={mockOnStatusChange}
          onDelete={mockOnDelete}
        />,
      );

      expect(screen.getByText("+ Tag")).toBeInTheDocument();
    });

    it('enters edit mode when "+ Tag" clicked', () => {
      render(
        <ContentItem
          content={mockContent}
          onStatusChange={mockOnStatusChange}
          onDelete={mockOnDelete}
        />,
      );

      const addTagButton = screen.getByText("+ Tag");
      fireEvent.click(addTagButton);

      expect(screen.getByPlaceholderText("Add tag...")).toBeInTheDocument();
      expect(screen.getByText("Add")).toBeInTheDocument();
      expect(screen.getByText("Done")).toBeInTheDocument();
    });

    it("shows remove buttons for tags in edit mode", () => {
      render(
        <ContentItem
          content={mockContent}
          onStatusChange={mockOnStatusChange}
          onDelete={mockOnDelete}
        />,
      );

      const addTagButton = screen.getByText("+ Tag");
      fireEvent.click(addTagButton);

      // Should show × button for each tag
      const removeButtons = screen.getAllByText("×");
