  describe("Highlights List", () => {
    const mockHighlights = [
      {
        id: "1",
        text: "First highlight text",
        start_offset: 0,
        end_offset: 20,
        color: "yellow",
        note: undefined,
        created_at: "2024-01-15T10:00:00Z",
