          {/* Description (if available from metadata extraction) */}
          {content.description && (
            <p className="text-sm text-gray-600 line-clamp-2">
              {content.description}
            </p>
          )}
        </div>

        {/* Right side: Thumbnail (if available) - aligned to top */}
        {content.thumbnail_url && (
          <div className="flex-shrink-0 hidden sm:block">
            <img
              src={content.thumbnail_url}
              alt={content.title || "thumbnail"}
              className="w-24 h-24 object-cover rounded-md"
            />
          </div>
        )}
      </div>

      <ConfirmModal
        isOpen={showDeleteModal}
        title="Delete Article"
        message="Are you sure you want to delete this article? This action cannot be undone."
        confirmText="Delete"
        cancelText="Cancel"
        danger={true}
        onConfirm={async () => {
          setShowDeleteModal(false);
          onDelete(content.id);
        }}
        onCancel={() => setShowDeleteModal(false)}
      />
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useToast } from "@/contexts/ToastContext";
import { highlightsAPI } from "@/lib/api";

interface HighlightToolbarProps {
  selection: {
    text: string;
    startOffset: number;
    endOffset: number;
    position: { x: number; y: number };
    existingHighlightId?: string;
    existingColor?: string;
    existingNote?: string;
  } | null;
  contentId: string;
  onClose: () => void;
  onHighlightCreated?: () => void;
}

const colors = [
  { name: "yellow", bg: "bg-yellow-200", hex: "#fef08a" },
  { name: "green", bg: "bg-green-200", hex: "#dcfce7" },
  { name: "blue", bg: "bg-blue-200", hex: "#bfdbfe" },
  { name: "pink", bg: "bg-pink-200", hex: "#fbcfe8" },
  { name: "purple", bg: "bg-purple-200", hex: "#e9d5ff" },
];

export default function HighlightToolbar({
  selection,
  contentId,
  onClose,
  onHighlightCreated,
}: HighlightToolbarProps) {
  const isEditing = !!selection?.existingHighlightId;
  const [selectedColor, setSelectedColor] = useState<string>("yellow");
  const [note, setNote] = useState<string>("");
  const [isLoading, setIsLoading] = useState(false);
  const [showNoteInput, setShowNoteInput] = useState(false);
  const { showToast } = useToast();

  // Reset state when selection changes
  useEffect(() => {
    if (selection) {
      setSelectedColor(selection.existingColor || "yellow");
      setNote(selection.existingNote || "");
      setShowNoteInput(!!selection.existingNote);
    }
  }, [
    selection?.existingHighlightId,
    selection?.startOffset,
    selection?.endOffset,
  ]);

  console.log("HighlightToolbar render:", { hasSelection: !!selection });

  if (!selection) return null;

  console.log("HighlightToolbar showing with selection:", selection);

  const handleSaveHighlight = async () => {
    try {
      setIsLoading(true);

      if (isEditing && selection.existingHighlightId) {
        // Update existing highlight
        console.log("Updating highlight:", {
          highlightId: selection.existingHighlightId,
          color: selectedColor,
          note,
        });

        await highlightsAPI.update(selection.existingHighlightId, {
          color: selectedColor,
          note: note || undefined,
        });

        console.log("Highlight updated");
        showToast("Highlight updated", "success");
      } else {
        // Create new highlight
        console.log("Creating highlight:", {
          contentId,
          text: selection.text,
          start_offset: selection.startOffset,
          end_offset: selection.endOffset,
          color: selectedColor,
        });

        const result = await highlightsAPI.create(contentId, {
          text: selection.text,
          start_offset: selection.startOffset,
          end_offset: selection.endOffset,
          color: selectedColor,
          note: note || undefined,
        });

        console.log("Highlight created:", result);
        showToast("Highlight saved", "success");
      }

      onHighlightCreated?.();
      onClose();
    } catch (error) {
      console.error("Error saving highlight:", error);
      showToast(
        error instanceof Error ? error.message : "Failed to save highlight",
        "error",
      );
    } finally {
      setIsLoading(false);
    }
  };

  const handleDeleteHighlight = async () => {
    if (!selection.existingHighlightId) return;

    if (!confirm("Remove this highlight?")) return;

    try {
      setIsLoading(true);
      await highlightsAPI.delete(selection.existingHighlightId);
      showToast("Highlight removed", "success");
      onHighlightCreated?.();
      onClose();
    } catch (error) {
      console.error("Error deleting highlight:", error);
      showToast("Failed to remove highlight", "error");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div
      className="highlight-toolbar fixed z-50 bg-white rounded-lg shadow-lg border border-gray-200 p-3 max-w-sm"
      style={{
        left: `${Math.max(20, selection.position.x - 150)}px`,
        top: `${selection.position.y - 60}px`,
      }}
    >
      {/* Color Picker */}
      <div className="flex gap-2 mb-3">
        {colors.map((color) => (
          <button
            key={color.name}
            onClick={() => setSelectedColor(color.name)}
            className={`w-6 h-6 rounded border-2 transition-all ${color.bg} ${
              selectedColor === color.name
                ? "border-gray-900 scale-110"
                : "border-gray-300 opacity-60 hover:opacity-100"
            }`}
            title={color.name}
            aria-label={color.name}
          />
        ))}
      </div>

      {/* Preview of selected text */}
      <div className="mb-3 p-2 bg-gray-50 rounded text-sm max-h-20 overflow-y-auto">
        <p className="text-gray-600 font-medium">
          "{selection.text.substring(0, 100)}
          {selection.text.length > 100 ? "..." : ""}"
        </p>
      </div>

      {/* Note Input */}
      {(showNoteInput || isEditing) && (
        <textarea
          placeholder={isEditing ? "Edit note..." : "Add a note (optional)"}
          value={note}
          onChange={(e) => setNote(e.target.value)}
          className="w-full mb-3 px-2 py-1 text-sm border border-gray-300 rounded focus:outline-none focus:ring-2 focus:ring-blue-400 resize-none"
          rows={2}
        />
      )}

      {/* Action Buttons */}
      <div className="flex gap-2">
        {!isEditing && (
          <button
            onClick={() => setShowNoteInput(!showNoteInput)}
            className="flex-1 text-sm px-2 py-1.5 rounded bg-gray-100 text-gray-700 hover:bg-gray-200 transition-colors"
          >
            {showNoteInput ? "✓ Note" : "Add Note"}
          </button>
        )}
        <button
          onClick={handleSaveHighlight}
          disabled={isLoading}
          className="flex-1 text-sm px-2 py-1.5 rounded bg-blue-500 text-white hover:bg-blue-600 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
        >
          {isLoading ? "Saving..." : isEditing ? "Update" : "Save"}
        </button>
        {isEditing && (
          <button
            onClick={handleDeleteHighlight}
            disabled={isLoading}
            className="flex-1 text-sm px-2 py-1.5 rounded bg-red-500 text-white hover:bg-red-600 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
          >
            Unhighlight
          </button>
        )}
        <button
          onClick={onClose}
          className="text-sm px-2 py-1.5 rounded bg-gray-100 text-gray-700 hover:bg-gray-200 transition-colors"
        >
          ✕
        </button>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect, useCallback } from "react";
import Link from "next/link";
import { ContentItem } from "@/types";
import { searchAPI, highlightsAPI } from "@/lib/api";
import HighlightToolbar from "./HighlightToolbar";
import HighlightRenderer from "./HighlightRenderer";
import HighlightsPanel from "./HighlightsPanel";

interface ReaderProps {
  content: ContentItem;
  onStatusChange: (updates: {
    is_read?: boolean;
    is_archived?: boolean;
    read_position?: number;
  }) => void;
}

export default function Reader({ content, onStatusChange }: ReaderProps) {
  // UI state
  const [fontSize, setFontSize] = useState<"small" | "medium" | "large">(
    "medium",
  );
  const [theme, setTheme] = useState<"light" | "sepia" | "dark">("light");

  // Similar articles state
  const [showSimilar, setShowSimilar] = useState(false);
  const [similarArticles, setSimilarArticles] = useState<
    Array<{
      item: ContentItem;
      similarity_score: number;
    }>
  >([]);
  const [loadingSimilar, setLoadingSimilar] = useState(false);

  const [selection, setSelection] = useState<{
    text: string;
    startOffset: number;
    endOffset: number;
    position: { x: number; y: number };
  } | null>(null);

  const [isCreatingHighlight, setIsCreatingHighlight] = useState(false);

  // Highlights state
  const [highlights, setHighlights] = useState<
    Array<{
      id: string;
      text: string;
      start_offset: number;
      end_offset: number;
      color: string;
      note?: string;
    }>
  >([]);
  const [loadingHighlights, setLoadingHighlights] = useState(false);

  // Store original plain text for offset calculation
  const [originalPlainText, setOriginalPlainText] = useState<string>("");

  // Highlights panel visibility
  const [showHighlightsPanel, setShowHighlightsPanel] = useState(false);

  // Fetch highlights when article loads
  const fetchHighlights = useCallback(async () => {
    try {
      setLoadingHighlights(true);
      console.log("Fetching highlights for content:", content.id);
      const data = await highlightsAPI.getByContent(content.id);
      console.log("Highlights fetched:", data);
      setHighlights(data);
    } catch (error) {
      console.error("Failed to load highlights:", error);
    } finally {
      setLoadingHighlights(false);
    }
  }, [content.id]);

  useEffect(() => {
    fetchHighlights();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [content.id]);

  // Extract original plain text when content loads
  useEffect(() => {
    if (!content.full_text) {
      setOriginalPlainText("");
      return;
    }

    // Parse the HTML to get plain text without any existing highlights
    const parser = new DOMParser();
    const doc = parser.parseFromString(content.full_text, "text/html");
    const plainText = doc.body.innerText || doc.body.textContent || "";
    setOriginalPlainText(plainText);
    console.log("Original plain text extracted:", {
      length: plainText.length,
      preview: plainText.substring(0, 100),
    });
  }, [content.full_text, content.id]); // Also depend on content.id to refresh on article change

  // Auto-mark as read when user opens the article
  useEffect(() => {
    if (!content.is_read) {
      // Wait 2 seconds before marking as read (ensures user is actually reading)
      const timer = setTimeout(() => {
        onStatusChange({ is_read: true });
      }, 2000);

      return () => clearTimeout(timer);
    }
  }, [content.is_read, onStatusChange]);

  // Track scroll position and save periodically
  useEffect(() => {
    let saveTimeout: NodeJS.Timeout;

    const handleScroll = () => {
      // Calculate scroll percentage
      const scrollTop = window.scrollY;
      const docHeight =
        document.documentElement.scrollHeight - window.innerHeight;
      const scrollPercent = docHeight > 0 ? scrollTop / docHeight : 0;

      // Debounce: save position 1 second after user stops scrolling
      clearTimeout(saveTimeout);
      saveTimeout = setTimeout(() => {
        // Only save if position changed significantly (more than 5%)
        if (
          content.read_position === undefined ||
          Math.abs(scrollPercent - (content.read_position || 0)) > 0.05
        ) {
          onStatusChange({ read_position: scrollPercent });
        }
      }, 1000);
    };

    window.addEventListener("scroll", handleScroll);

    return () => {
      window.removeEventListener("scroll", handleScroll);
      clearTimeout(saveTimeout);
    };
  }, [content.id, content.read_position, onStatusChange]);

  // Restore scroll position when article loads
  useEffect(() => {
    if (content.read_position && content.read_position > 0) {
      // Store position in a const to ensure it's not undefined
      const savedPosition = content.read_position;

      // Wait for content to render, then scroll
      setTimeout(() => {
        const docHeight =
          document.documentElement.scrollHeight - window.innerHeight;
        const scrollTo = docHeight * savedPosition;
        window.scrollTo({ top: scrollTo, behavior: "smooth" });
      }, 100);
    }
  }, [content.id]); // Only run when article changes

  // highlight
  useEffect(() => {
    const handleMouseUp = (e: MouseEvent) => {
      // Check if click was on the toolbar - if so, ignore
      const target = e.target as HTMLElement;
      if (target.closest(".highlight-toolbar")) {
        return;
      }

      const selection = window.getSelection();

      // Check if user clicked on an existing highlight (without selecting new text)
      if (!selection || selection.toString().length === 0) {
        // Check if the click was on a highlighted span
        if (target.dataset.highlightId) {
          const clickedHighlight = highlights.find(
            (h) => h.id === target.dataset.highlightId,
          );
          if (clickedHighlight) {
            // Show toolbar for editing this highlight
            const rect = target.getBoundingClientRect();
            setSelection({
              text: clickedHighlight.text,
              startOffset: clickedHighlight.start_offset,
              endOffset: clickedHighlight.end_offset,
              position: {
                x: rect.left + rect.width / 2,
                y: rect.top - 10,
              },
              existingHighlightId: clickedHighlight.id,
              existingColor: clickedHighlight.color,
              existingNote: clickedHighlight.note,
            } as any);
            return;
          }
        }
        setSelection(null);
        return;
      }

      const offsets = getTextOffsets();
      if (!offsets) return;

      // Get toolbar position (show near selection)
      const range = selection.getRangeAt(0);
      const rect = range.getBoundingClientRect();

      setSelection({
        text: offsets.selectedText,
        startOffset: offsets.startOffset,
        endOffset: offsets.endOffset,
        position: {
          x: rect.left + rect.width / 2,
          y: rect.top - 10, // Above selection
        },
      });
    };

    document.addEventListener("mouseup", handleMouseUp);
    return () => document.removeEventListener("mouseup", handleMouseUp);
  }, [highlights]);

  /**
   * Fetch similar articles when user requests them
   */
  const handleFindSimilar = async () => {
    if (similarArticles.length > 0) {
      // Toggle if already loaded
      setShowSimilar(!showSimilar);
      return;
    }

    try {
      setLoadingSimilar(true);
      const results = await searchAPI.findSimilar(content.id);
      setSimilarArticles(results);
      setShowSimilar(true);
    } catch (error) {
      console.error("Failed to find similar articles:", error);
      alert(
        "Failed to find similar articles. This article may not have embeddings yet.",
      );
    } finally {
      setLoadingSimilar(false);
    }
  };

  const fontSizeClasses = {
    small: "text-base",
    medium: "text-lg",
    large: "text-xl",
  };

  const themeClasses = {
    light: "bg-white text-gray-900",
    sepia: "bg-amber-50 text-amber-950",
    dark: "bg-gray-900 text-gray-100",
  };

  const linkColorClasses = {
    light: "text-blue-600 hover:text-blue-800",
    sepia: "text-amber-700 hover:text-amber-900",
    dark: "text-blue-400 hover:text-blue-300",
  };

  const scrollToHighlight = (highlight: {
    id: string;
    text: string;
    start_offset: number;
    end_offset: number;
    color: string;
    note?: string;
  }) => {
    // Find the span element with this highlight ID
    const highlightEl = document.querySelector(
      `[data-highlight-id="${highlight.id}"]`,
    );

    if (highlightEl) {
      highlightEl.scrollIntoView({ behavior: "smooth", block: "center" });
      // Flash animation to draw attention
      highlightEl.classList.add("ring-2", "ring-blue-500");
      setTimeout(() => {
        highlightEl.classList.remove("ring-2", "ring-blue-500");
      }, 1500);
    }
  };

  const getTextOffsets = () => {
    const selection = window.getSelection();
    if (!selection || selection.toString().length === 0) return null;

    // Get selected text
    const selectedText = selection.toString();

    // If we don't have original plain text yet, extract it on the fly
    let plainText = originalPlainText;
    if (!plainText && content.full_text) {
      const parser = new DOMParser();
      const doc = parser.parseFromString(content.full_text, "text/html");
      plainText = doc.body.innerText || doc.body.textContent || "";
    }

    if (!plainText) {
      console.error("Cannot extract plain text from content");
      return null;
    }

    // Simple approach: Find the selected text in the plain text
    // Since the user is selecting from the rendered content which might have highlights,
    // we need to search for the text in the original

    // Try to find exact match first
    const exactMatchIndex = plainText.indexOf(selectedText);

    if (exactMatchIndex !== -1) {
      console.log("getTextOffsets (exact match):", {
        selectedText: selectedText.substring(0, 50),
        startOffset: exactMatchIndex,
        endOffset: exactMatchIndex + selectedText.length,
        plainTextLength: plainText.length,
      });

      return {
        selectedText,
        startOffset: exactMatchIndex,
        endOffset: exactMatchIndex + selectedText.length,
      };
    }

    // If exact match fails, try to find it by context
    // Get some context before and after from the rendered DOM
    const contentEl = document.getElementById("reader-content");
    if (!contentEl) return null;

    const range = selection.getRangeAt(0);
    const preCaretRange = range.cloneRange();
    preCaretRange.selectNodeContents(contentEl);
    preCaretRange.setEnd(range.startContainer, range.startOffset);

    // Get last 100 chars before selection as context
    const contextBefore = preCaretRange.toString().slice(-100);

    // Find this context in the original text
    const contextIndex = plainText.indexOf(contextBefore);

    if (contextIndex !== -1) {
      const startOffset = contextIndex + contextBefore.length;
      const endOffset = startOffset + selectedText.length;

      console.log("getTextOffsets (context match):", {
        selectedText: selectedText.substring(0, 50),
        startOffset,
        endOffset,
        plainTextLength: plainText.length,
      });

      return { selectedText, startOffset, endOffset };
    }

    // Last resort: search for a cleaned version of the text
    const cleanText = (text: string) => text.replace(/\s+/g, " ").trim();
    const cleanedSelected = cleanText(selectedText);
    const cleanedPlain = cleanText(plainText);

    const cleanedIndex = cleanedPlain.indexOf(cleanedSelected);

    if (cleanedIndex !== -1) {
      // Map back to original text position (approximate)
      console.warn("Using approximate offset based on cleaned text");
      return {
        selectedText,
        startOffset: cleanedIndex,
        endOffset: cleanedIndex + cleanedSelected.length,
      };
    }

    console.error("Could not find selected text in original content");
    return null;
  };

  return (
    <div className={`min-h-screen ${themeClasses[theme]} transition-colors`}>
      <HighlightToolbar
        selection={selection}
        contentId={content.id}
        onClose={() => setSelection(null)}
        onHighlightCreated={fetchHighlights}
      />
      {/* Sticky Header with Controls */}
      <div
        className={`sticky top-0 z-10 ${themeClasses[theme]} border-b ${theme === "dark" ? "border-gray-700" : "border-gray-200"} shadow-sm`}
      >
        <div className="max-w-4xl mx-auto px-4 py-3">
          <div className="flex items-center justify-between">
            {/* Back Button */}
            <a
              href="/dashboard"
              className={`${linkColorClasses[theme]} text-sm font-medium hover:underline`}
            >
              ← Back to Queue
            </a>

            {/* Reading Controls */}
            <div className="flex items-center gap-4">
              {/* Font Size Control */}
              <div className="flex items-center gap-2">
                <span className="text-xs font-medium opacity-70">Size:</span>
                <div className="flex gap-1">
                  {(["small", "medium", "large"] as const).map((size) => (
                    <button
                      key={size}
                      onClick={() => setFontSize(size)}
                      className={`px-2 py-1 rounded text-xs font-medium transition-colors ${
                        fontSize === size
                          ? theme === "dark"
                            ? "bg-gray-700 text-white"
                            : "bg-gray-200 text-gray-900"
                          : theme === "dark"
                            ? "bg-gray-800 text-gray-400 hover:bg-gray-700"
                            : "bg-gray-100 text-gray-600 hover:bg-gray-200"
                      }`}
                    >
                      {size === "small" ? "A" : size === "medium" ? "A" : "A"}
                    </button>
                  ))}
                </div>
              </div>

              {/* Theme Control */}
              <div className="flex items-center gap-2">
                <span className="text-xs font-medium opacity-70">Theme:</span>
                <div className="flex gap-1">
                  {(["light", "sepia", "dark"] as const).map((t) => (
                    <button
                      key={t}
                      onClick={() => setTheme(t)}
                      className={`w-6 h-6 rounded border-2 transition-all ${
                        theme === t
                          ? "border-blue-500 scale-110"
                          : "border-gray-300 opacity-60 hover:opacity-100"
                      } ${
                        t === "light"
                          ? "bg-white"
                          : t === "sepia"
                            ? "bg-amber-50"
                            : "bg-gray-900"
                      }`}
                      title={t.charAt(0).toUpperCase() + t.slice(1)}
                    />
                  ))}
                </div>
              </div>

              {/* Action Buttons */}
              <div
                className="flex items-center gap-2 flex-wrap"
                style={{
                  borderColor: theme === "dark" ? "#374151" : "#e5e7eb",
                }}
              >
                <button
                  onClick={() => setShowHighlightsPanel(!showHighlightsPanel)}
                  className={`text-sm px-3 py-1.5 rounded-md transition-colors ${
                    showHighlightsPanel
                      ? theme === "dark"
                        ? "bg-yellow-900 text-yellow-200 hover:bg-yellow-800"
                        : "bg-yellow-100 text-yellow-700 hover:bg-yellow-200"
                      : theme === "dark"
                        ? "bg-gray-800 text-gray-300 hover:bg-gray-700"
                        : "bg-gray-100 text-gray-700 hover:bg-gray-200"
                  }`}
                >
                  {showHighlightsPanel ? "Hide" : "Show"} Highlights{" "}
                  {highlights.length > 0 && `(${highlights.length})`}
                </button>
                <button
                  onClick={() =>
                    onStatusChange({ is_archived: !content.is_archived })
                  }
                  className={`text-sm px-3 py-1.5 rounded-md transition-colors ${
                    content.is_archived
                      ? theme === "dark"
                        ? "bg-blue-900 text-blue-200 hover:bg-blue-800"
                        : "bg-blue-100 text-blue-700 hover:bg-blue-200"
                      : theme === "dark"
                        ? "bg-gray-800 text-gray-300 hover:bg-gray-700"
                        : "bg-gray-100 text-gray-700 hover:bg-gray-200"
                  }`}
                >
                  {content.is_archived ? "Unarchive" : "Archive"}
                </button>
                <button
                  onClick={handleFindSimilar}
                  disabled={loadingSimilar}
                  className={`text-sm px-3 py-1.5 rounded-md transition-colors ${
                    theme === "dark"
                      ? "bg-purple-900 text-purple-200 hover:bg-purple-800"
                      : "bg-purple-100 text-purple-700 hover:bg-purple-200"
                  } disabled:opacity-50 disabled:cursor-not-allowed`}
                >
                  {loadingSimilar
                    ? "Loading..."
                    : showSimilar
                      ? "Hide Similar"
                      : "Find Similar"}
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Highlights Panel Sidebar */}
      {showHighlightsPanel && (
        <div
          className={`fixed right-0 top-0 h-full w-80 ${themeClasses[theme]} border-l ${theme === "dark" ? "border-gray-700" : "border-gray-200"} shadow-xl z-20 overflow-hidden flex flex-col`}
        >
          <HighlightsPanel
            highlights={highlights}
            onHighlightClick={scrollToHighlight}
            onHighlightDeleted={fetchHighlights}
            onHighlightUpdated={fetchHighlights}
          />
        </div>
      )}

      {/* Article Content */}
      <article
        className={`max-w-4xl mx-auto px-4 py-8 transition-all ${showHighlightsPanel ? "mr-80" : ""}`}
      >
        {/* Article Header */}
        <header className="mb-8">
          <h1
            className={`font-bold mb-4 leading-tight ${fontSize === "small" ? "text-3xl" : fontSize === "medium" ? "text-4xl" : "text-5xl"}`}
          >
            {content.title || "Untitled Article"}
          </h1>

          {/* Metadata */}
          <div className="flex items-center gap-4 text-sm opacity-70 mb-4">
            {content.reading_time_minutes && (
              <span>{content.reading_time_minutes} min read</span>
            )}
            <span>•</span>
            <span>{new Date(content.created_at).toLocaleDateString()}</span>
          </div>

          {/* Original URL */}
          <a
            href={content.original_url}
            target="_blank"
            rel="noopener noreferrer"
            className={`${linkColorClasses[theme]} text-sm hover:underline inline-flex items-center gap-1`}
          >
            View original
            <svg
              className="w-4 h-4"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14"
              />
            </svg>
          </a>

          {/* Thumbnail */}
          {content.thumbnail_url && (
            <div className="mt-6">
              <img
                src={content.thumbnail_url}
                alt=""
                className="w-full rounded-lg"
              />
            </div>
          )}
        </header>

        {/* Description */}
        {content.description && (
          <div
            className={`${fontSizeClasses[fontSize]} leading-relaxed mb-8 opacity-80 italic border-l-4 pl-4 ${theme === "dark" ? "border-gray-700" : "border-gray-300"}`}
          >
            {content.description}
          </div>
        )}

        {/* Main Content */}
        <div
          id="reader-content"
          className={`prose ${theme === "dark" ? "prose-invert" : theme === "sepia" ? "prose-amber" : ""} max-w-none ${fontSizeClasses[fontSize]} leading-relaxed`}
        >
          {content.full_text ? (
            <HighlightRenderer
              html={content.full_text}
              highlights={highlights}
              onHighlightClick={(highlight) => {
                console.log("Clicked highlight:", highlight);
              }}
            />
          ) : (
            <div className="text-center py-12 opacity-60">
              <p>Full content not available yet.</p>
              <p className="text-sm mt-2">
                {content.processing_status === "processing" &&
                  "Content is being extracted..."}
                {content.processing_status === "pending" &&
                  "Content extraction is pending..."}
                {content.processing_status === "failed" &&
                  "Content extraction failed. Please visit the original URL."}
              </p>
            </div>
          )}
        </div>

        {/* Similar Articles Section */}
        {showSimilar && similarArticles.length > 0 && (
          <div
            className={`mt-12 pt-8 border-t ${theme === "dark" ? "border-gray-700" : "border-gray-300"}`}
          >
            <h2 className="text-2xl font-bold mb-6">Similar Articles</h2>
            <div className="grid gap-4">
              {similarArticles.map(({ item, similarity_score }) => (
                <Link
                  key={item.id}
                  href={`/content/${item.id}`}
                  className={`block p-4 rounded-lg border transition-colors ${
                    theme === "dark"
                      ? "bg-gray-800 border-gray-700 hover:bg-gray-750"
                      : "bg-white border-gray-200 hover:bg-gray-50"
                  }`}
                >
                  <div className="flex items-start gap-4">
                    {item.thumbnail_url && (
                      <img
                        src={item.thumbnail_url}
                        alt=""
                        className="w-20 h-20 object-cover rounded flex-shrink-0"
                      />
                    )}
                    <div className="flex-1 min-w-0">
                      <h3
                        className={`font-semibold mb-1 ${linkColorClasses[theme]}`}
                      >
                        {item.title || "Untitled"}
                      </h3>
                      {item.description && (
                        <p className="text-sm opacity-70 line-clamp-2 mb-2">
                          {item.description}
                        </p>
                      )}
                      <div className="flex items-center gap-3 text-xs opacity-60">
                        <span className="text-purple-600 dark:text-purple-400 font-medium">
                          {Math.round(similarity_score * 100)}% similar
                        </span>
                        {item.reading_time_minutes && (
                          <>
                            <span>•</span>
                            <span>{item.reading_time_minutes} min read</span>
                          </>
                        )}
                      </div>
                    </div>
                  </div>
                </Link>
              ))}
            </div>
          </div>
        )}
      </article>
    </div>
  );
}

"use client";

import { useState, useRef, useEffect } from "react";
import { useRouter } from "next/navigation";
import { searchAPI } from "@/lib/api";
import Link from "next/link";

/**
 * SearchBar Component
 *
 * Provides semantic search functionality:
 * - Debounced search (waits 300ms after user stops typing)
 * - Dropdown with live results
 * - Shows similarity scores
 * - Click result to navigate to article
 */

interface SearchResult {
  item: {
    id: string;
    title: string;
    description: string | null;
    thumbnail_url: string | null;
    reading_time_minutes: number | null;
  };
  similarity_score: number;
}

export default function SearchBar() {
  const router = useRouter();
  const [query, setQuery] = useState("");
  const [results, setResults] = useState<SearchResult[]>([]);
  const [loading, setLoading] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const searchRef = useRef<HTMLDivElement>(null);

  /**
   * Debounced search - waits for user to stop typing
   * This prevents making too many API calls while typing
   */
  useEffect(() => {
    // Don't search if query is too short
    if (query.length < 3) {
      setResults([]);
      setShowResults(false);
      return;
    }

    // Set a timeout to delay the search
    const timeoutId = setTimeout(async () => {
      try {
        setLoading(true);
        const searchResults = await searchAPI.semantic(query);
        setResults(searchResults);
        setShowResults(true);
      } catch (error) {
        console.error("Search failed:", error);
        setResults([]);
      } finally {
        setLoading(false);
      }
    }, 300); // Wait 300ms after user stops typing

    // Cleanup: cancel the timeout if user types again
    return () => clearTimeout(timeoutId);
  }, [query]);

  /**
   * Close dropdown when clicking outside
   */
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (
        searchRef.current &&
        !searchRef.current.contains(event.target as Node)
      ) {
        setShowResults(false);
      }
    };

    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  /**
   * Handle selecting a result
   */
  const handleSelectResult = (id: string) => {
    setShowResults(false);
    setQuery("");
    router.push(`/content/${id}`);
  };

  /**
   * Format similarity score as percentage
   */
  const formatScore = (score: number) => {
    return `${Math.round(score * 100)}% match`;
  };

  return (
    <div ref={searchRef} className="relative w-full max-w-2xl">
      {/* Search Input */}
      <div className="relative">
        <input
          type="text"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder="Search your content..."
          className="w-full px-4 py-2 pr-10 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
        />

        {/* Search Icon / Loading Spinner */}
        <div className="absolute right-3 top-1/2 transform -translate-y-1/2">
          {loading ? (
            <div className="animate-spin h-5 w-5 border-2 border-blue-500 border-t-transparent rounded-full"></div>
          ) : (
            <svg
              className="h-5 w-5 text-gray-400"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"
              />
            </svg>
          )}
        </div>
      </div>

      {/* Results Dropdown */}
      {showResults && results.length > 0 && (
        <div className="absolute w-full mt-2 bg-white border border-gray-200 rounded-lg shadow-lg max-h-96 overflow-y-auto z-50">
          {results.map((result) => (
            <button
              key={result.item.id}
              onClick={() => handleSelectResult(result.item.id)}
              className="w-full text-left px-4 py-3 hover:bg-gray-50 transition-colors border-b border-gray-100 last:border-b-0"
            >
              <div className="flex items-start gap-3">
                {/* Thumbnail (if available) */}
                {result.item.thumbnail_url && (
                  <img
                    src={result.item.thumbnail_url}
                    alt=""
                    className="w-12 h-12 object-cover rounded flex-shrink-0"
                  />
                )}

                {/* Content Info */}
                <div className="flex-1 min-w-0">
                  <h4 className="font-medium text-gray-900 truncate">
                    {result.item.title || "Untitled"}
                  </h4>
                  {result.item.description && (
                    <p className="text-sm text-gray-600 line-clamp-2">
                      {result.item.description}
                    </p>
                  )}
                  <div className="flex items-center gap-3 mt-1">
                    <span className="text-xs text-blue-600 font-medium">
                      {formatScore(result.similarity_score)}
                    </span>
                    {result.item.reading_time_minutes && (
                      <span className="text-xs text-gray-500">
                        {result.item.reading_time_minutes} min read
                      </span>
                    )}
                  </div>
                </div>
              </div>
            </button>
          ))}
        </div>
      )}

      {/* No Results Message */}
      {showResults && !loading && query.length >= 3 && results.length === 0 && (
        <div className="absolute w-full mt-2 bg-white border border-gray-200 rounded-lg shadow-lg p-4 z-50">
          <p className="text-gray-500 text-center">
            No results found for "{query}"
          </p>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { usePathname, useSearchParams } from "next/navigation";
import { listsAPI } from "@/lib/api";
import { useLists } from "@/contexts/ListsContext";

/**
 * Sidebar Navigation Component
 *
 * Provides navigation links to:
 * - Main content views (All, Unread, Archived)
 * - User's custom lists
 *
 * Shows content counts for quick overview
 * Responsive: collapsible on mobile
 */

interface ListItem {
  id: string;
  name: string;
  content_count: number;
}

export default function Sidebar() {
  const pathname = usePathname();
  const searchParams = useSearchParams();
  const [lists, setLists] = useState<ListItem[]>([]);
  const [loading, setLoading] = useState(true);
  const { listCounts, setListCount } = useLists();

  useEffect(() => {
    fetchLists();
  }, []);

  const fetchLists = async () => {
    try {
      const data = await listsAPI.getAll();
      setLists(data);
      data.forEach((list: ListItem) => {
        setListCount(list.id, list.content_count);
      });
    } catch (err) {
      console.error("Failed to fetch lists:", err);
    } finally {
      setLoading(false);
    }
  };

  /**
   * Helper to determine if a link is active
   * Handles both exact path matches and query parameter matches
   */
  const isActive = (path: string) => {
    // For paths with query params, check if current URL matches
    if (path.includes("?")) {
      // Extract base path and search params
      const [basePath, queryPart] = path.split("?");
      // Check if pathname matches
      if (pathname !== basePath) return false;
      const linkParams = new URLSearchParams(queryPart);

      // Check if all link params match current params
      for (const [key, value] of linkParams.entries()) {
        if (searchParams.get(key) !== value) return false;
      }
      return true;
    }

    // For paths without query params, check exact match and no query params
    return pathname === path && !searchParams.toString();
  };

  /**
   * Base classes for navigation links
   * Active links get blue background, inactive get hover effect
   */
  const linkClasses = (path: string) => {
    return `flex items-center justify-between px-4 py-2 rounded-md text-sm font-medium transition-colors ${
      isActive(path)
        ? "bg-blue-600 text-white"
        : "text-gray-700 hover:bg-gray-100"
    }`;
  };

  return (
    <aside className="hidden lg:block w-64 bg-white border-r border-gray-200 h-screen sticky top-0 overflow-y-auto">
      <div className="p-4 space-y-6">
        {/* App Title */}
        <div className="px-4">
          <h1 className="text-xl font-bold text-gray-900">Content Queue</h1>
        </div>

        {/* Main Navigation Links */}
        <nav className="space-y-1">
          <Link href="/dashboard" className={linkClasses("/dashboard")}>
            <span>All Content</span>
          </Link>

          <Link
            href="/dashboard?filter=unread"
            className={linkClasses("/dashboard?filter=unread")}
          >
            <span>Unread</span>
          </Link>

          <Link
            href="/dashboard?filter=archived"
            className={linkClasses("/dashboard?filter=archived")}
          >
            <span>Archived</span>
          </Link>
        </nav>

        {/* Divider */}
        <div className="border-t border-gray-200"></div>

        {/* Lists Section */}
        <div className="space-y-2">
          <div className="flex items-center justify-between px-4">
            <h2 className="text-xs font-semibold text-gray-500 uppercase tracking-wider">
              Lists
            </h2>
            <Link
              href="/lists"
              className="text-blue-600 hover:text-blue-800 text-sm"
            >
              Manage
            </Link>
          </div>

          {/* Lists Loading State */}
          {loading && (
            <div className="px-4 py-2 text-sm text-gray-500">
              Loading lists...
            </div>
          )}

          {/* Lists Navigation */}
          {!loading && lists.length === 0 && (
            <div className="px-4 py-2 text-sm text-gray-500">
              No lists yet.{" "}
              <Link href="/lists" className="text-blue-600 hover:text-blue-800">
                Create one
              </Link>
            </div>
          )}

          {!loading && lists.length > 0 && (
            <nav className="space-y-1">
              {lists.map((list) => (
                <Link
                  key={list.id}
                  href={`/lists/${list.id}`}
                  className={linkClasses(`/lists/${list.id}`)}
                >
                  <span className="truncate">{list.name}</span>
                  <span className="ml-2 px-2 py-0.5 text-xs rounded-full bg-gray-200 text-gray-700">
                    {listCounts[list.id] ?? list.content_count}
                  </span>
                </Link>
              ))}
            </nav>
          )}
        </div>
      </div>
    </aside>
  );
}

"use client";

import {
  createContext,
  useContext,
  useState,
  useEffect,
  ReactNode,
} from "react";
import { authAPI } from "@/lib/api";
import { User } from "@/types";

interface AuthContextType {
  user: User | null;
  login: (email: string, password: string) => Promise<void>;
  register: (
    email: string,
    password: string,
    fullName?: string,
  ) => Promise<void>;
  logout: () => void;
  isLoading: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    // Check if user is logged in on mount
    const token = localStorage.getItem("token");
    if (token) {
      fetchUser();
    } else {
      setIsLoading(false);
    }
  }, []);

  const fetchUser = async () => {
    try {
      const userData = await authAPI.getCurrentUser();
      setUser(userData);
    } catch (error) {
      localStorage.removeItem("token");
    } finally {
      setIsLoading(false);
    }
  };

  const login = async (email: string, password: string) => {
    await authAPI.login(email, password);
    await fetchUser();
  };

  const register = async (
    email: string,
    password: string,
    fullName?: string,
  ) => {
    await authAPI.register(fullName || email, email, password);
    // Auto-login after registration
    await login(email, password);
  };

  const logout = () => {
    authAPI.logout();
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, login, register, logout, isLoading }}>
      {children}
    </AuthContext.Provider>
  );
}

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
};

